// app/dashboard/page.tsx — Server Component, no directive needed
import { Suspense } from 'react';
import { DashboardStats } from '@/components/dashboard/stats';
import { Counter } from '@/components/counter'; // client component lives inside

export default async function DashboardPage() {
  const session = await getServerSession();
  if (!session) redirect('/login');

  return (
    <div className="container py-8">
      <Suspense fallback={<div>Loading stats...</div>}>
        <DashboardStats userId={session.user.id} />
      </Suspense>
      <Counter /> {/* 'use client' is in counter.tsx, not here */}
    </div>
  );
}

'use client'; // wrong — kills SSR for the entire page
export default function DashboardPage() {
  return <div><Counter /></div>;
}

// lib/queries.ts — deduplicated with React.cache
import { cache } from 'react';
import { db } from '@/lib/db';

export const getUser = cache(async (id: string) => {
  return db.user.findUnique({ where: { id } });
});

// Server Component — direct DB access
export async function UserCard({ id }: { id: string }) {
  const user = await getUser(id); // cached per-request
  return <div>{user?.name}</div>;
}

'use client';
export function UserList() {
  const [users, setUsers] = useState([]);
  useEffect(() => {
    fetch('/api/users').then(r => r.json()).then(setUsers);
  }, []);
  return <ul>{users.map(u => <li key={u.id}>{u.name}</li>)}</ul>;
}

// layout.tsx — no data props, children fetch their own
export default function Layout({ children }: { children: React.ReactNode }) {
  return <div><Header />{children}</div>;
}

// Header fetches session independently
async function Header() {
  const session = await getServerSession();
  return <header>{session?.user.name}</header>;
}
